def test_callable_flag_value_default(runner):
    class Value:
        def __call__(self):
            raise AssertionError("instantiated")

    flag_value = Value()

    @click.command()
    @click.option("--value", "flag", flag_value=flag_value, default=True, type=UNPROCESSED)
    def cli(flag):
        click.echo(flag is flag_value)

    result = runner.invoke(cli, [])
    assert not result.exception
    assert result.output == "True\n"


def test_callable_flag_value_default_map_and_show_default(runner):
    class Value:
        def __call__(self):
            raise AssertionError("instantiated")

    flag_value = Value()

    @click.command()
    @click.option(
        "--value",
        "flag",
        flag_value=flag_value,
        default=True,
        show_default=True,
        type=UNPROCESSED,
    )
    def cli(flag):
        click.echo(flag)

    result = runner.invoke(cli, [], default_map={"flag": "mapped"})
    assert not result.exception
    assert result.output == "mapped\n"

    result = runner.invoke(cli, ["--help"], default_map={"flag": "mapped"})
    assert not result.exception
    assert "[default: mapped]" in result.output


